import{_ as a,o as s,c as e,ae as n}from"./chunks/framework.B6gjLfeO.js";const u=JSON.parse('{"title":"2세대: 컨텍스트 엔지니어링","description":"","frontmatter":{},"headers":[],"relativePath":"part2-evolution/context-engineering.md","filePath":"part2-evolution/context-engineering.md"}'),i={name:"part2-evolution/context-engineering.md"};function o(r,t,l,d,p,h){return s(),e("div",null,[...t[0]||(t[0]=[n(`<h1 id="_2세대-컨텍스트-엔지니어링" tabindex="-1">2세대: 컨텍스트 엔지니어링 <a class="header-anchor" href="#_2세대-컨텍스트-엔지니어링" aria-label="Permalink to &quot;2세대: 컨텍스트 엔지니어링&quot;">​</a></h1><blockquote><p><strong>스토리</strong>: &quot;AI에게 기억을 심어주자&quot;</p></blockquote><h2 id="정의" tabindex="-1">정의 <a class="header-anchor" href="#정의" aria-label="Permalink to &quot;정의&quot;">​</a></h2><p><strong>컨텍스트 엔지니어링(Context Engineering)</strong>이란, AI가 프로젝트의 <strong>맥락(코드베이스, 규칙, 히스토리)</strong>을 이해하도록 <strong>환경을 설계하는 기술</strong>입니다.</p><p>1세대가 &quot;한 번의 질문을 잘 하는 것&quot;이었다면, 2세대는 &quot;<strong>지속적으로 AI가 우리 프로젝트를 이해하도록 만드는 것</strong>&quot;입니다.</p><h2 id="프롬프트-vs-컨텍스트-엔지니어링" tabindex="-1">프롬프트 vs 컨텍스트 엔지니어링 <a class="header-anchor" href="#프롬프트-vs-컨텍스트-엔지니어링" aria-label="Permalink to &quot;프롬프트 vs 컨텍스트 엔지니어링&quot;">​</a></h2><table tabindex="0"><thead><tr><th>구분</th><th>프롬프트 엔지니어링</th><th>컨텍스트 엔지니어링</th></tr></thead><tbody><tr><td>초점</td><td>일회성 요청 최적화</td><td>지속적 환경 최적화</td></tr><tr><td>범위</td><td>단일 대화</td><td>프로젝트 전체</td></tr><tr><td>저장</td><td>없음 (매번 재입력)</td><td>파일로 영구 저장</td></tr><tr><td>비유</td><td>잘 지시하기</td><td>매뉴얼 만들기</td></tr></tbody></table><h2 id="핵심-개념" tabindex="-1">핵심 개념 <a class="header-anchor" href="#핵심-개념" aria-label="Permalink to &quot;핵심 개념&quot;">​</a></h2><h3 id="_1-instruction-파일" tabindex="-1">1. Instruction 파일 <a class="header-anchor" href="#_1-instruction-파일" aria-label="Permalink to &quot;1. Instruction 파일&quot;">​</a></h3><p>프로젝트 루트에 AI를 위한 <strong>지침 파일</strong>을 두는 방법입니다:</p><table tabindex="0"><thead><tr><th>파일명</th><th>도구</th></tr></thead><tbody><tr><td><code>CLAUDE.md</code></td><td>Claude Code</td></tr><tr><td><code>GEMINI.md</code></td><td>Gemini CLI</td></tr><tr><td><code>.cursorrules</code></td><td>Cursor</td></tr><tr><td><code>.github/copilot-instructions.md</code></td><td>GitHub Copilot</td></tr></tbody></table><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;"># CLAUDE.md 예시</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## 프로젝트 개요</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">React + TypeScript + Supabase로 구성된 TODO 앱입니다.</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## 코딩 규칙</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 함수형 컴포넌트만 사용</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Tailwind CSS v4 사용</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 한국어 주석 작성</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> 에러 핸들링 필수</span></span></code></pre></div><p>이 파일이 있으면, AI가 <strong>대화 시작 시 자동으로 읽고</strong> 프로젝트 맥락을 파악합니다.</p><h3 id="_2-rules-파일" tabindex="-1">2. Rules 파일 <a class="header-anchor" href="#_2-rules-파일" aria-label="Permalink to &quot;2. Rules 파일&quot;">​</a></h3><p>특정 상황에서만 적용되는 <strong>규칙 파일</strong>을 분리합니다:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>.cursor/rules/</span></span>
<span class="line"><span>├── react-component.md    # React 컴포넌트 작성 규칙</span></span>
<span class="line"><span>├── api-endpoint.md       # API 엔드포인트 규칙</span></span>
<span class="line"><span>└── database-schema.md    # DB 스키마 규칙</span></span></code></pre></div><h3 id="_3-mcp-model-context-protocol" tabindex="-1">3. MCP (Model Context Protocol) <a class="header-anchor" href="#_3-mcp-model-context-protocol" aria-label="Permalink to &quot;3. MCP (Model Context Protocol)&quot;">​</a></h3><p>AI에게 <strong>외부 도구를 연결</strong>하는 표준 프로토콜입니다.</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>AI ←→ MCP ←→ Supabase (데이터베이스)</span></span>
<span class="line"><span>             Context7 (공식 문서)</span></span>
<span class="line"><span>             Serena (코드 분석)</span></span>
<span class="line"><span>             GitHub (이슈, PR)</span></span></code></pre></div><p>MCP를 통해 AI가 직접 데이터베이스를 조회하거나, 공식 문서를 참조하거나, 코드를 분석할 수 있습니다.</p><h3 id="_4-rag-retrieval-augmented-generation" tabindex="-1">4. RAG (Retrieval Augmented Generation) <a class="header-anchor" href="#_4-rag-retrieval-augmented-generation" aria-label="Permalink to &quot;4. RAG (Retrieval Augmented Generation)&quot;">​</a></h3><p>AI가 <strong>필요한 정보를 필요한 시점에 검색</strong>하도록 하는 기술입니다. 전체 코드베이스를 한꺼번에 넣는 대신, 관련된 부분만 찾아서 참조합니다.</p><h2 id="한계점" tabindex="-1">한계점 <a class="header-anchor" href="#한계점" aria-label="Permalink to &quot;한계점&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">⚠️ 컨텍스트 엔지니어링의 구조적 한계</p><h3 id="_1-만능-ai의-한계" tabindex="-1">1. 만능 AI의 한계 <a class="header-anchor" href="#_1-만능-ai의-한계" aria-label="Permalink to &quot;1. 만능 AI의 한계&quot;">​</a></h3><p>아무리 맥락을 잘 줘도, <strong>한 AI가 프론트엔드 + 백엔드 + DB + 보안 + 디자인</strong>을 모두 잘할 수는 없습니다.</p><h3 id="_2-토큰-비용-폭증" tabindex="-1">2. 토큰 비용 폭증 <a class="header-anchor" href="#_2-토큰-비용-폭증" aria-label="Permalink to &quot;2. 토큰 비용 폭증&quot;">​</a></h3><p>맥락이 커질수록, 매 요청마다 전송하는 토큰 수가 늘어나 <strong>비용이 기하급수적으로 증가</strong>합니다.</p><h3 id="_3-역할-혼동" tabindex="-1">3. 역할 혼동 <a class="header-anchor" href="#_3-역할-혼동" aria-label="Permalink to &quot;3. 역할 혼동&quot;">​</a></h3><p>하나의 AI에게 &quot;프론트엔드도 해줘, 백엔드도 해줘, 리뷰도 해줘&quot;라고 하면, <strong>모든 것을 어중간하게</strong> 하는 결과가 나옵니다.</p><h3 id="_4-워크플로우-부재" tabindex="-1">4. 워크플로우 부재 <a class="header-anchor" href="#_4-워크플로우-부재" aria-label="Permalink to &quot;4. 워크플로우 부재&quot;">​</a></h3><p>&quot;먼저 설계하고 → 계획 세우고 → 구현하고 → 리뷰한다&quot; 같은 <strong>구조화된 작업 흐름</strong>이 없습니다.</p></div><h2 id="비유로-이해하기" tabindex="-1">비유로 이해하기 <a class="header-anchor" href="#비유로-이해하기" aria-label="Permalink to &quot;비유로 이해하기&quot;">​</a></h2><p>컨텍스트 엔지니어링은 마치 <strong>프리랜서에게 회사 매뉴얼을 주는 것</strong>과 같습니다:</p><ul><li>✅ 매번 반복 설명할 필요 없음</li><li>✅ 일관된 스타일로 작업</li><li>❌ 그래도 모든 분야를 한 사람이 하기엔 한계</li><li>❌ 체계적인 업무 프로세스가 없음</li></ul><blockquote><p><em>&quot;한 사람에게 매뉴얼을 줘봤자, 이제는 팀이 필요하다.&quot;</em></p><p>→ 이것이 <strong>3세대: 하네스 엔지니어링</strong>의 출발점입니다.</p></blockquote>`,28)])])}const g=a(i,[["render",o]]);export{u as __pageData,g as default};
